diff --git a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
index f2d6e268743e..d67e66c7f976 100644
--- a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
+++ b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
@@ -1565,6 +1565,12 @@ static bool checkOrAndOpImpliedByOther(
     SmallVectorImpl<ReproducerEntry> &ReproducerCondStack,
     SmallVectorImpl<StackEntry> &DFSInStack) {
   Instruction *JoinOp = CB.getContextInst();
+
+  // This logic is not valid for `or disjoint` because it can introduce poison.
+  if (JoinOp->getOpcode() == Instruction::Or &&
+      JoinOp->getMetadata(LLVMContext::MD_noduplicate))
+    return false;
+
   CmpInst *CmpToCheck = cast<CmpInst>(CB.getInstructionToSimplify());
   unsigned OtherOpIdx = JoinOp->getOperand(0) == CmpToCheck ? 1 : 0;

